19	        Self { ents: BoundedArr::new() }
20	    }
21	
22	    pub fn insert(&mut self, k: &str, v: i32) -> Result<(), PortError> {
23	        let key = VKey::from_str(k)?;
24	        for i in 0..self.ents.len() {
25	            let entry = self.ents.get_mut(i).expect("vmap: len invariant");
26	            if entry.0 == key {
27	                entry.1 = v;
28	                return Ok(());
29	            }
30	        }
31	        self.ents.push((key, v))
32	    }
33	
34	    pub fn get(&self, k: &str) -> Option<i32> {
35	        let key = VKey::from_str(k).ok()?;
36	        for entry in self.ents.iter() {
37	            if entry.0 == key {
38	                return Some(entry.1);
39	            }
40	        }
41	        None
42	    }
43	
44	    pub fn len(&self) -> usize {
45	        self.ents.len()
46	    }
47	
48	    pub fn is_empty(&self) -> bool {
49	        self.ents.is_empty()
50	    }
51	
52	    pub fn iter(&self) -> impl Iterator<Item = (&VKey, i32)> + '_ {
53	        self.ents.iter().map(|(k, v)| (k, *v))
54	    }
55	}
56	
57	impl<const N: usize> Default for Vmap<N> {
58	    fn default() -> Self {
59	        Self::new()
60	    }
61	}
62	
63	#[cfg(test)]
64	mod tests {
65	    use super::*;
66	
67	    #[test]
68	    fn insert_then_get() {
69	        let mut m: Vmap<8> = Vmap::new();
70	        m.insert("a", 1).unwrap();
71	        m.insert("b", 2).unwrap();
72	        assert_eq!(m.get("a"), Some(1));
73	        assert_eq!(m.get("b"), Some(2));
74	        assert_eq!(m.get("c"), None);
75	        assert_eq!(m.len(), 2);
76	    }
