79	    fn insert_overwrites_existing_key() {
80	        let mut m: Vmap<4> = Vmap::new();
81	        m.insert("x", 1).unwrap();
82	        m.insert("x", 99).unwrap();
83	        assert_eq!(m.get("x"), Some(99));
84	        assert_eq!(m.len(), 1);
85	    }
