88	    fn overflow_at_capacity() {
89	        let mut m: Vmap<2> = Vmap::new();
90	        m.insert("a", 1).unwrap();
91	        m.insert("b", 2).unwrap();
92	        assert_eq!(m.insert("c", 3), Err(PortError::Overflow));
93	    }
